import UIKit

class UniversalLinkHandler {
    static func handleUniversalLink(url: URL) -> Bool {
        guard let components = NSURLComponents(url: url, resolvingAgainstBaseURL: true) else { return false }

        switch components.host {
            case "myapp.com":
                switch components.path {
                    case "/profile":
                        // Parse the profile ID from the URL
                        let profileID = Int(components.queryItems?.first(where: { $0.name == "id" })?.value ?? "")

                        // Navigate to the profile view controller with the parsed profile ID
                        let profileViewController = ProfileViewController()
                        profileViewController.profileID = profileID
                        navigationController?.pushViewController(profileViewController, animated: true)

                    case "/payment/confirm":
                        // Parse the payment ID from the URL
                        let paymentID = Int(components.queryItems?.first(where: { $0.name == "id" })?.value ?? "")

                        // Navigate to the payment confirmation view controller with the parsed payment ID
                        let paymentConfirmationViewController = PaymentConfirmationViewController()
                        paymentConfirmationViewController.paymentID = paymentID
                        navigationController?.pushViewController(paymentConfirmationViewController, animated: true)

                    case "/admin/settings":
                        // Navigate to the admin settings view controller
                        let adminSettingsViewController = AdminSettingsViewController()
                        navigationController?.pushViewController(adminSettingsViewController, animated: true)

                    default:
                        return false
                }
            default:
                return false
        }

        return true
    }
}